  let target;
  let array;
  let left;
  let right;
  let mid;
  let boxes;

  document.getElementById('start').addEventListener('click', startSearch);
  document.getElementById('step').addEventListener('click', stepSearch);

  function startSearch() {
    target = parseInt(document.getElementById('target').value);
    array = document.getElementById('array').value.split(',').map(Number);
    if (array.length === 0) return;

    // Ensure array is sorted
    array.sort((a, b) => a - b);

    left = 0;
    right = array.length - 1;
    updateDisplay();
    document.getElementById('step').disabled = false;
    document.getElementById('start').disabled = true;
    document.getElementById('result').innerText = '';
  }

  function stepSearch() {
    if (left > right) {
      document.getElementById('result').innerText = 'Not found!';
      document.getElementById('step').disabled = true;
      return;
    }

    mid = Math.floor((left + right) / 2);
    if (array[mid] === target) {
      document.getElementById('result').innerText = 'Found!';
      document.getElementById('step').disabled = true;
    } else if (array[mid] < target) {
      left = mid + 1;
    } else {
      right = mid - 1;
    }
    updateDisplay();
  }

  function updateDisplay() {
    let html = '';
    boxes = array.map((num, index) => {
      let className = '';
      if (index >= left && index <= right) className += ' active';
      if (index === mid) className += ' middle';
      return `<div class="box${className}">${num}</div>`;
    });
    html = boxes.join(' ');
    document.getElementById('arrayDisplay').innerHTML = html;
  }
