        table.appendChild(tbody);
        table.insertBefore(tbody, table.querySelector('thead'));
      }
      const tr = document.createElement('tr');
      tbody.appendChild(tr);
      cells.forEach(cell => {
        const td = document.createElement('td');
        td.textContent = cell;
        tr.appendChild(td);
      });
    }
  }
}

function parseRow(row) {
  const escaped = row.match(/"((?:\\.|[^"])*)"/g);
  let offset = 0;
  const cells = [];

  while (offset < row.length) {
    if (row[offset] === '"') {
      const match = row.substring(offset).match(/^"((?:\\.|[^"])*)"(,|$)/);
      if (match) {
        cells.push(unescape(match[1].replace(/\\(.)/g, '$1')));
        offset += match[0].length;
      } else {
        throw new Error('Malformed CSV');
      }
    } else {
      const cellMatch = row.substring(offset).match(/^[^,]*($|,)/);
      cells.push(cellMatch[0].replace(/,$/, ''));
      offset += cellMatch[0].length;
    }
  }

  return cells;
}

function unescape(str) {
  return str.replace(/\\(.)/g, '$1');
}
