            let pivot = arr[high];
            let i = low - 1;
            for (let j = low; j < high; j++) {
                steps++;
                if (arr[j] < pivot) {
                    i++;
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                }
            }
            [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];
            return i + 1;
        }

        // Mergesort
        function* mergesort(arr, low, high) {
            let steps = 0;
            if (low < high) {
                let mid = Math.floor((low + high) / 2);
                yield* mergesort(arr, low, mid);
                yield* mergesort(arr, mid + 1, high);
                yield* merge(arr, low, mid, high, steps);
            }
        }

        function* merge(arr, low, mid, high, steps) {
            let left = arr.slice(low, mid + 1);
            let right = arr.slice(mid + 1, high + 1);
            let i = 0, j = 0, k = low;
            while (i < left.length && j < right.length) {
                steps++;
                if (left[i] <= right[j]) {
                    arr[k] = left[i];
                    i++;
                } else {
                    arr[k] = right[j];
                    j++;
                }
                k++;
                yield [arr, steps];
            }
            while (i < left.length) {
                arr[k] = left[i];
                i++;
                k++;
                yield [arr, steps];
            }
            while (j < right.length) {
                arr[k] = right[j];
                j++;
                k++;
                yield [arr, steps];
            }
        }

        // Draw the bars
        function drawBars(arr1, arr2, arr3) {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            let barWidth = canvas.width / arr1.length / 3;
            for (let i = 0; i < arr1.length; i++) {
                ctx.fillStyle = 'blue';
                ctx.fillRect(i * barWidth * 3, canvas.height - arr1[i] * 2, barWidth, arr1[i] * 2);
                ctx.fillStyle = 'red';
                ctx.fillRect(i * barWidth * 3 + barWidth, canvas.height - arr2[i] * 2, barWidth, arr2[i] * 2);
                ctx.fillStyle = 'green';
                ctx.fillRect(i * barWidth * 3 + barWidth * 2, canvas.height - arr3[i] * 2, barWidth, arr3[i] * 2);
            }
        }

        // Main function
        async function main() {
            let arr = generateRandomArray(20);
            let arr2 = [...arr];
            let arr3 = [...arr];

            let bubbleSortGenerator = bubbleSort(arr);
            let quicksortGenerator = quicksort(arr2, 0, arr2.length - 1);
            let mergesortGenerator = mergesort(arr3, 0, arr3.length - 1);

            let bubbleSortSteps = 0;
            let quicksortSteps = 0;
            let mergesortSteps = 0;

            while (true) {
                let bubbleSortResult = bubbleSortGenerator.next();
                let quicksortResult = quicksortGenerator.next();
                let mergesortResult = mergesortGenerator.next();

                if (bubbleSortResult.done) {
                    bubbleSortSteps = bubbleSortResult.value;
                    break;
                }
                if (quicksortResult.done) {
                    quicksortSteps = quicksortResult.value;
                    break;
                }
                if (mergesortResult.done) {
                    mergesortSteps = mergesortResult.value;
                    break;
                }

                drawBars(bubbleSortResult.value[0], quicksortResult.value[0], mergesortResult.value[0]);
                document.getElementById('step-counters').innerHTML = 
                    `Bubble sort steps: ${bubbleSortResult.value[1]} | Quicksort steps: ${quicksortResult.value[1]} | Mergesort steps: ${mergesortResult.value[1]}`;
                await new Promise(resolve => setTimeout(resolve, 50));
            }

            drawBars(arr, arr2, arr3);
            document.getElementById('step-counters').innerHTML = 
                `Bubble sort steps: ${bubbleSortSteps} | Quicksort steps: ${quicksortSteps} | Mergesort steps: ${mergesortSteps}`;
            document.getElementById('complexity-explanation').innerHTML = 
                `Time complexities: Bubble sort - O(n^2), Quicksort - O(n log n) on average, Mergesort - O(n log n)`;
        }

        main();
    </script>
