        drawBranch(100, -Math.PI / 2, depth);
    }

    function drawBranch(length, angle, depth) {
        if (depth === 0) return;
        ctx.beginPath();
        ctx.moveTo(0, 0);
        ctx.lineTo(length * Math.cos(angle), length * Math.sin(angle));
        ctx.stroke();
        ctx.translate(length * Math.cos(angle), length * Math.sin(angle));
        drawBranch(length * 0.7, angle - Math.PI / 6, depth - 1);
        drawBranch(length * 0.7, angle + Math.PI / 6, depth - 1);
        ctx.translate(-length * Math.cos(angle), -length * Math.sin(angle));
    }

    // Initial draw
    drawTree(parseInt(depthSlider.value));
</script>

</body>
</html>
```

This code snippet creates a basic fractal tree with branches that split at angles, using recursion to draw the tree to a specified depth. The recursion depth is controlled by a slider, and changing the slider value redraws the tree. An explanation section is included to discuss recursion depth limits and how to mitigate stack overflow errors.

