    if (depth === 0) continue;
    ctx.beginPath();
    ctx.moveTo(0, 0);
    ctx.lineTo(0, -length);
    ctx.stroke();
    ctx.translate(0, -length);
    stack.push({ length: length * 0.7, depth: depth - 1 });
    stack.push({ length: length * 0.7, depth: depth - 1 });
    ctx.translate(0, length);
  }
}
```
This iterative solution uses a stack to store the branch information and avoids the recursion depth limit.

